                    bit_cnt = 0;
                }
                // Skip the second chip of this bit
                if (symbols[i].duration1 >= (CHIP_TICKS - 12)) {
                    // Symbol contains both chips.
                    i++;
                } else {
                    // Second chip is in next symbol?
                    i++;
                }
            } else if (dur >= (DOUBLE_CHIP_TICKS - 12)) {
                // Two same chips in a row! 
                // This happens when bit transitions 1->1 or 0->0.
                // 1(HL) followed by 1(HL) -> H L H L. First chip is H.
                // 0(LH) followed by 0(LH) -> L H L H. First chip is L.
                // BUT if we have 1(HL) followed by 0(LH) -> H L L H. (LL = 8us).
                // Our decoder is a bit simplified here.
                sof_found = false; i++; 
            } else {
                if (payload_len >= 7) goto end;
                sof_found = false; i++;
            }
        }
    }
end:
    if (payload_len >= 7) {
        uint8_t opt[7] = { 0x01, 0xFF, 0xFF, 0xFF, 0xFF, 0x40, 0x00 };
        esp3_send_packet(ESP3_TYPE_RADIO_ERP1, payload, payload_len, opt, 7);
    }
}
